begin;
create table if not exists public.lead_attribution_touches(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,lead_id uuid not null references public.leads(id) on delete cascade,touch_kind text not null check(touch_kind in('first_touch','campaign_touch','source_change','manual_touch')),source text not null,channel text,campaign_id uuid references public.campaigns(id) on delete set null,campaign_external_id text,adset_external_id text,ad_external_id text,form_external_id text,page_external_id text,development_id uuid references public.developments(id) on delete set null,event_key text not null,occurred_at timestamptz not null,recorded_by uuid references public.profiles(id),evidence text,created_at timestamptz not null default now(),unique(organization_id,event_key));alter table public.leads add column if not exists first_attribution_id uuid references public.lead_attribution_touches(id) on delete restrict,add column if not exists last_attribution_id uuid references public.lead_attribution_touches(id) on delete restrict;create index if not exists lead_attribution_timeline_idx on public.lead_attribution_touches(organization_id,lead_id,occurred_at,id);alter table public.lead_attribution_touches enable row level security;drop policy if exists lead_attribution_touches_scope on public.lead_attribution_touches;create policy lead_attribution_touches_scope on public.lead_attribution_touches for select to authenticated using(organization_id=(select public.current_organization_id())and(select private.can_view_lead(lead_id)));revoke all on public.lead_attribution_touches from anon;revoke insert,update,delete on public.lead_attribution_touches from authenticated;grant select on public.lead_attribution_touches to authenticated;
create or replace function public.record_lead_attribution_touch(p_actor_id uuid,p_organization_id uuid,p_lead_id uuid,p_touch_kind text,p_source text,p_channel text,p_campaign_id uuid,p_development_id uuid,p_external jsonb,p_event_key text,p_occurred_at timestamptz,p_evidence text)returns jsonb language plpgsql security definer set search_path='' as $$declare target_id uuid;is_first boolean;begin if p_actor_id is not null and not exists(select 1 from public.profiles p where p.id=p_actor_id and p.organization_id=p_organization_id and p.active=true and(p.id=(select l.assigned_to from public.leads l where l.id=p_lead_id and l.organization_id=p_organization_id)or coalesce(p.commercial_role,case p.role when'admin'then'director'else p.role end)in('director','superintendent','manager')))then raise exception 'attribution_actor_forbidden';end if;if not exists(select 1 from public.leads where id=p_lead_id and organization_id=p_organization_id)or p_touch_kind not in('first_touch','campaign_touch','source_change','manual_touch')or char_length(trim(coalesce(p_source,'')))<2 or char_length(trim(coalesce(p_event_key,'')))<5 or p_actor_id is not null and char_length(trim(coalesce(p_evidence,'')))<10 then raise exception 'attribution_payload_invalid';end if;perform pg_advisory_xact_lock(hashtextextended(p_organization_id::text||':'||p_lead_id::text,0));select not exists(select 1 from public.lead_attribution_touches where organization_id=p_organization_id and lead_id=p_lead_id)into is_first;insert into public.lead_attribution_touches(organization_id,lead_id,touch_kind,source,channel,campaign_id,campaign_external_id,adset_external_id,ad_external_id,form_external_id,page_external_id,development_id,event_key,occurred_at,recorded_by,evidence)values(p_organization_id,p_lead_id,case when is_first then'first_touch'else p_touch_kind end,trim(p_source),nullif(trim(p_channel),''),p_campaign_id,nullif(p_external->>'campaignId',''),nullif(p_external->>'adsetId',''),nullif(p_external->>'adId',''),nullif(p_external->>'formId',''),nullif(p_external->>'pageId',''),p_development_id,trim(p_event_key),coalesce(p_occurred_at,now()),p_actor_id,nullif(trim(p_evidence),''))on conflict(organization_id,event_key)do nothing returning id into target_id;if target_id is null then select id into target_id from public.lead_attribution_touches where organization_id=p_organization_id and event_key=p_event_key;return jsonb_build_object('touchId',target_id,'duplicatePrevented',true,'firstTouchImmutable',true);end if;update public.leads set first_attribution_id=coalesce(first_attribution_id,target_id),last_attribution_id=target_id where id=p_lead_id and organization_id=p_organization_id;return jsonb_build_object('touchId',target_id,'firstTouch',is_first,'firstTouchImmutable',true,'lastTouchUpdated',true,'auditable',true);end $$;
create or replace function private.capture_lead_attribution()returns trigger language plpgsql security definer set search_path='' as $$declare meta jsonb:=coalesce(new.metadata->'meta','{}'::jsonb);kind text;event_key text;begin kind:=case when tg_op='INSERT'then'first_touch'when new.campaign_id is distinct from old.campaign_id then'campaign_touch'else'source_change'end;event_key:=case when tg_op='INSERT'then'lead-created:'||new.id::text else'lead-attribution:'||new.id::text||':'||txid_current()::text end;perform public.record_lead_attribution_touch(null,new.organization_id,new.id,kind,coalesce(nullif(new.source,''),'Não informada'),coalesce(nullif(meta->>'channel',''),case when lower(coalesce(new.source,''))like'%meta%'then'meta'when lower(coalesce(new.source,''))like'%google%'then'google'when lower(coalesce(new.source,''))like'%whatsapp%'then'whatsapp'end),new.campaign_id,new.development_id,meta,event_key,case when tg_op='INSERT'then new.created_at else now()end,'Captura automática da origem canônica');return new;end $$;
drop trigger if exists capture_lead_attribution_after_write on public.leads;drop trigger if exists capture_lead_attribution_after_insert on public.leads;drop trigger if exists capture_lead_attribution_after_update on public.leads;create trigger capture_lead_attribution_after_insert after insert on public.leads for each row execute function private.capture_lead_attribution();create trigger capture_lead_attribution_after_update after update of source,campaign_id,development_id,metadata on public.leads for each row when(old.source is distinct from new.source or old.campaign_id is distinct from new.campaign_id or old.development_id is distinct from new.development_id or old.metadata->'meta'is distinct from new.metadata->'meta')execute function private.capture_lead_attribution();
insert into public.lead_attribution_touches(organization_id,lead_id,touch_kind,source,channel,campaign_id,campaign_external_id,adset_external_id,ad_external_id,form_external_id,page_external_id,development_id,event_key,occurred_at,evidence)select l.organization_id,l.id,'first_touch',coalesce(nullif(l.source,''),'Não informada'),case when lower(coalesce(l.source,''))like'%meta%'then'meta'when lower(coalesce(l.source,''))like'%google%'then'google'when lower(coalesce(l.source,''))like'%whatsapp%'then'whatsapp'end,l.campaign_id,nullif(l.metadata->'meta'->>'campaignId',''),nullif(l.metadata->'meta'->>'adsetId',''),nullif(l.metadata->'meta'->>'adId',''),nullif(l.metadata->'meta'->>'formId',''),nullif(l.metadata->'meta'->>'pageId',''),l.development_id,'backfill-first:'||l.id::text,l.created_at,'Backfill da origem histórica disponível'from public.leads l where not exists(select 1 from public.lead_attribution_touches t where t.organization_id=l.organization_id and t.lead_id=l.id);update public.leads l set first_attribution_id=t.id,last_attribution_id=t.id from public.lead_attribution_touches t where t.lead_id=l.id and t.organization_id=l.organization_id and t.touch_kind='first_touch'and l.first_attribution_id is null;
revoke all on function public.record_lead_attribution_touch(uuid,uuid,uuid,text,text,text,uuid,uuid,jsonb,text,timestamptz,text)from public,anon,authenticated;grant execute on function public.record_lead_attribution_touch(uuid,uuid,uuid,text,text,text,uuid,uuid,jsonb,text,timestamptz,text)to service_role;
commit;
